require 'minitest/autorun'
require 'json'
require_relative '../lib/selo/ie'

class IeTest < Minitest::Test
  VECTOR = JSON.parse(File.read(File.join(__dir__, '../vectors/ie.json'))).freeze

  def test_validate
    VECTOR['validate'].each do |c|
      assert_equal c['valid'], Selo::IE.valid?(c['input']), "validate #{c['input'].inspect}"
    end
  end

  def test_format
    VECTOR['format'].each do |c|
      if c.key?('error')
        assert_raises(ArgumentError) { Selo::IE.format(c['input']) }
      else
        assert_equal c['output'], Selo::IE.format(c['input']), "format #{c['input'].inspect}"
      end
    end
  end

  def test_generate
    100.times do
      val = Selo::IE.generate
      assert Selo::IE.valid?(val), "generate produced invalid: #{val.inspect}"
    end
  end
end
